  1	import React, { FC, useState } from 'react';
  2	import { Trans } from 'react-i18next';
  3	import produce from 'immer';
  4	
  5	import { V1CPU, V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
  6	import CPUInput from '@kubevirt-utils/components/CPUMemoryModal/components/CPUInput/CPUInput';
  7	import MemoryInput from '@kubevirt-utils/components/CPUMemoryModal/components/MemoryInput/MemoryInput';
  8	import { DEFAULT_NAMESPACE } from '@kubevirt-utils/constants/constants';
  9	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 10	import { getLabel } from '@kubevirt-utils/resources/shared';
 11	import { getCPU, getMemory, VM_TEMPLATE_ANNOTATION } from '@kubevirt-utils/resources/vm';
 12	import { ensurePath } from '@kubevirt-utils/utils/utils';
 13	import {
 14	  Alert,
 15	  AlertVariant,
 16	  Button,
 17	  ButtonVariant,
 18	  Modal,
 19	  ModalVariant,
 20	} from '@patternfly/react-core';
 21	
 22	import useTemplateDefaultCpuMemory from './hooks/useTemplateDefaultCpuMemory';
 23	import { getMemorySize } from './utils/CpuMemoryUtils';
 24	
 25	import './cpu-memory-modal.scss';
 26	
 27	type VirtuaMachineOrVoid = V1VirtualMachine | void;
 28	
 29	type CPUMemoryModalProps = {
 30	  isOpen: boolean;
 31	  onClose: () => void;
 32	  onSubmit: (updatedVM: V1VirtualMachine) => Promise<VirtuaMachineOrVoid> | VirtuaMachineOrVoid;
 33	  templateNamespace?: string;
 34	  vm: V1VirtualMachine;
 35	};
 36	
 37	const CPUMemoryModal: FC<CPUMemoryModalProps> = ({
 38	  isOpen,
 39	  onClose,
 40	  onSubmit,
 41	  templateNamespace = DEFAULT_NAMESPACE,
 42	  vm,
 43	}) => {
 44	  const { t } = useKubevirtTranslation();
 45	
 46	  const [updateInProcess, setUpdateInProcess] = useState<boolean>(false);
 47	  const [updateError, setUpdateError] = useState<string>();
 48	
 49	  const { size, unit } = getMemorySize(getMemory(vm));
 50	  const [memory, setMemory] = useState<number>(size || undefined);
 51	  const [memoryUnit, setMemoryUnit] = useState<string>(unit || undefined);
 52	  const [cpu, setCPU] = useState<V1CPU>(getCPU(vm));
 53	
 54	  const {
 55	    data: templateDefaultsData,
 56	    error: defaultLoadError,
 57	    loaded: defaultsLoaded,
 58	  } = useTemplateDefaultCpuMemory(
 59	    vm?.metadata?.labels?.['vm.kubevirt.io/template'],
 60	    vm?.metadata?.labels?.['vm.kubevirt.io/template.namespace'] || templateNamespace,
 61	  );
 62	  const { defaultCpu, defaultMemory } = templateDefaultsData || {};
 63	  const { size: defaultMemorySize, unit: defaultMemoryUnit } = defaultMemory || {};
 64	
 65	  const templateName = getLabel(vm, VM_TEMPLATE_ANNOTATION);
 66	
 67	  const handleSubmit = async () => {
 68	    setUpdateInProcess(true);
 69	    setUpdateError(null);
 70	
 71	    const updatedVM = produce<V1VirtualMachine>(vm, (vmDraft: V1VirtualMachine) => {
 72	      ensurePath(vmDraft, [
 73	        'spec.template.spec.domain.cpu',
 74	        'spec.template.spec.domain.memory.guest',
 75	      ]);
 76	
 77	      vmDraft.spec.template.spec.domain.cpu = cpu;
 78	      vmDraft.spec.template.spec.domain.memory.guest = `${memory}${memoryUnit}`;
 79	    });
 80	
 81	    try {
 82	      await onSubmit(updatedVM);
 83	
 84	      setUpdateInProcess(false);
 85	      onClose();
 86	    } catch (error) {
 87	      setUpdateInProcess(false);
 88	      setUpdateError(error.message);
 89	    }
 90	  };
 91	
 92	  return (
 93	    <Modal
 94	      actions={[
 95	        <Button
 96	          isDisabled={updateInProcess}
 97	          isLoading={updateInProcess}
 98	          key="confirm"
 99	          onClick={handleSubmit}
100	          variant={ButtonVariant.primary}
101	        >
102	          {t('Save')}
103	        </Button>,
104	        <Button
105	          isDisabled={
106	            !templateName || !defaultsLoaded || !defaultCpu || !defaultMemory || defaultLoadError
107	          }
108	          onClick={() => {
109	            setCPU(defaultCpu);
110	            setMemory(defaultMemorySize);
111	            setMemoryUnit(defaultMemoryUnit);
112	          }}
113	          isLoading={templateName && !defaultsLoaded}
114	          key="default"
115	          variant={ButtonVariant.secondary}
116	        >
117	          {t('Restore template settings')}
118	        </Button>,
119	        <Button key="cancel" onClick={onClose} variant="link">
120	          {t('Cancel')}
121	        </Button>,
122	      ]}
123	      className="cpu-memory-modal"
124	      isOpen={isOpen}
125	      onClose={onClose}
126	      title={t('Edit CPU | Memory')}
127	      variant={ModalVariant.small}
128	      width="650px"
129	    >
130	      <Alert
131	        title={
132	          <Trans ns="plugin__kubevirt-plugin" t={t}>
133	            Updates to the sockets value are applied immediately.{<br />}To apply changes to the
134	            cores or threads values, you must restart the VirtualMachine.
135	          </Trans>
136	        }
137	        isInline
138	        variant={AlertVariant.info}
139	      />
140	      <div className="inputs">
141	        <CPUInput currentCPU={getCPU(vm)} setUserEnteredCPU={setCPU} userEnteredCPU={cpu} />
142	        <MemoryInput
143	          memory={memory}
144	          memoryUnit={memoryUnit}
145	          setMemory={setMemory}
146	          setMemoryUnit={setMemoryUnit}
147	        />
148	      </div>
149	      {updateError && (
150	        <Alert isInline title={t('Error')} variant="danger">
151	          {updateError}
152	        </Alert>
153	      )}
154	    </Modal>
155	  );
156	};
157	
158	export default CPUMemoryModal;

